import json
import pandas as pd
import re

# Load the data
hours_file = var_functions.query_db:4
if isinstance(hours_file, str) and hours_file.endswith('.json'):
    with open(hours_file, 'r') as f:
        hours_data = json.load(f)
else:
    hours_data = var_functions.query_db:4

# Load reviews
reviews_file = var_functions.query_db:22
if isinstance(reviews_file, str) and reviews_file.endswith('.json'):
    with open(reviews_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_file

# Parse reviews
reviews_df = pd.DataFrame(reviews)
reviews_df['rating'] = pd.to_numeric(reviews_df['rating'])
avg_ratings = reviews_df.groupby('gmap_id')['rating'].agg(['mean', 'count']).reset_index()
avg_ratings.columns = ['gmap_id', 'avg_rating', 'review_count']

# Function to check if truly open AFTER 6PM (not exactly at 6PM)
weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

def truly_open_after_6pm(hours_str):
    if not hours_str or hours_str == 'None':
        return False

    try:
        hours_list = eval(hours_str)
        for day, hours in hours_list:
            if day in weekdays and hours != 'Closed':
                if hours == 'Open 24 hours':
                    return True

                dash = '–' if '–' in hours else '-'
                if dash in hours:
                    parts = hours.split(dash)
                    if len(parts) >= 2:
                        close_time = parts[1].strip()
                        if 'PM' in close_time:
                            hour_part = close_time.replace('PM', '').replace(' ', '')
                            if ':' in hour_part:
                                hour = int(hour_part.split(':')[0])
                            else:
                                hour = int(hour_part)

                            if hour != 12:
                                hour += 12

                            # Must be AFTER 6PM (hour > 18)
                            if hour > 18:
                                return True
    except:
        return False
    return False

# Filter businesses that are truly open after 6PM
valid_businesses = []
for business in hours_data:
    if truly_open_after_6pm(business['hours']):
        valid_businesses.append(business)

print(f"Found {len(valid_businesses)} businesses truly open after 6PM")

# Merge with ratings
businesses_df = pd.DataFrame(valid_businesses)
df_final = pd.merge(businesses_df, avg_ratings, on='gmap_id', how='left')

# Remove businesses with no reviews or NaN ratings
df_final = df_final.dropna(subset=['avg_rating'])

# Sort by rating (descending) and get top 5
df_top5 = df_final.sort_values('avg_rating', ascending=False).head(5)

print("Top 5 businesses:")
for idx, row in df_top5.iterrows():
    print(f"  {row['name']}: {row['avg_rating']:.2f} stars ({row['review_count']} reviews)")

# Format result
result = []
for idx, row in df_top5.iterrows():
    result.append({
        'name': row['name'],
